/**
 * Fleet API Routes
 *
 * CRUD operations for train assets.
 */

import { Hono } from "hono";
import { zValidator } from "@hono/zod-validator";
import { z } from "zod";
import { getCollection, COLLECTIONS } from "../db/connection";
import type { Asset } from "@uptime/types";

const fleet = new Hono();

// Validation schemas
const assetSchema = z.object({
  id: z.string(),
  assetNumber: z.string(),
  assetType: z.string(),
  carsCount: z.number().int().positive(),
  currentMileageKm: z.number().min(0),
  avgDailyMileageKm: z.number().min(0),
  lastMaintenanceDate: z.string(),
  status: z.string().default("operational"),
  lastMaintenanceKm: z.record(z.string(), z.number()).optional(),
  metadata: z.record(z.string(), z.unknown()).optional(),
});

const updateAssetSchema = assetSchema.partial().omit({ id: true });

/**
 * GET /fleet - List all assets
 */
fleet.get("/", async (c) => {
  const collection = getCollection<Asset>(COLLECTIONS.ASSETS);
  const assets = await collection.find({}).toArray();

  return c.json({
    data: assets,
    total: assets.length,
  });
});

/**
 * GET /fleet/summary - Get fleet summary statistics
 */
fleet.get("/summary", async (c) => {
  const collection = getCollection<Asset>(COLLECTIONS.ASSETS);
  const assets = await collection.find({}).toArray();

  const alstom = assets.filter((a) => a.assetType === "ALSTOM");
  const kinki = assets.filter((a) => a.assetType === "KINKI");

  const avgMileage =
    assets.length > 0
      ? Math.round(
          assets.reduce((sum, a) => sum + a.currentMileageKm, 0) / assets.length
        )
      : 0;

  const alstomAvgMileage =
    alstom.length > 0
      ? Math.round(
          alstom.reduce((sum, a) => sum + a.currentMileageKm, 0) / alstom.length
        )
      : 0;

  const kinkiAvgMileage =
    kinki.length > 0
      ? Math.round(
          kinki.reduce((sum, a) => sum + a.currentMileageKm, 0) / kinki.length
        )
      : 0;

  return c.json({
    total: assets.length,
    alstomCount: alstom.length,
    kinkiCount: kinki.length,
    avgMileage,
    alstomAvgMileage,
    kinkiAvgMileage,
    operational: assets.filter((a) => a.status === "operational").length,
    inMaintenance: assets.filter((a) => a.status === "in_maintenance").length,
  });
});

/**
 * GET /fleet/:id - Get single asset by ID
 */
fleet.get("/:id", async (c) => {
  const id = c.req.param("id");
  const collection = getCollection<Asset>(COLLECTIONS.ASSETS);
  const asset = await collection.findOne({ id });

  if (!asset) {
    return c.json({ error: "Asset not found" }, 404);
  }

  return c.json(asset);
});

/**
 * POST /fleet - Create new asset
 */
fleet.post("/", zValidator("json", assetSchema), async (c) => {
  const asset = c.req.valid("json") as Asset;
  const collection = getCollection<Asset>(COLLECTIONS.ASSETS);

  // Check if asset already exists
  const existing = await collection.findOne({ id: asset.id });
  if (existing) {
    return c.json({ error: "Asset already exists" }, 409);
  }

  await collection.insertOne(asset);
  return c.json(asset, 201);
});

/**
 * POST /fleet/bulk - Create multiple assets
 */
fleet.post(
  "/bulk",
  zValidator("json", z.object({ assets: z.array(assetSchema) })),
  async (c) => {
    const { assets } = c.req.valid("json");
    const collection = getCollection<Asset>(COLLECTIONS.ASSETS);

    // Delete existing assets and insert new ones (for seeding)
    await collection.deleteMany({});
    if (assets.length > 0) {
      await collection.insertMany(assets as Asset[]);
    }

    return c.json({
      message: `Inserted ${assets.length} assets`,
      count: assets.length,
    });
  }
);

/**
 * PUT /fleet/:id - Update asset
 */
fleet.put("/:id", zValidator("json", updateAssetSchema), async (c) => {
  const id = c.req.param("id");
  const updates = c.req.valid("json");
  const collection = getCollection<Asset>(COLLECTIONS.ASSETS);

  const result = await collection.findOneAndUpdate(
    { id },
    { $set: updates },
    { returnDocument: "after" }
  );

  if (!result) {
    return c.json({ error: "Asset not found" }, 404);
  }

  return c.json(result);
});

/**
 * DELETE /fleet/:id - Delete asset
 */
fleet.delete("/:id", async (c) => {
  const id = c.req.param("id");
  const collection = getCollection<Asset>(COLLECTIONS.ASSETS);

  const result = await collection.deleteOne({ id });

  if (result.deletedCount === 0) {
    return c.json({ error: "Asset not found" }, 404);
  }

  return c.json({ message: "Asset deleted", id });
});

export { fleet };

