/**
 * Solver API Routes
 */

import { Hono } from "hono";
import { zValidator } from "@hono/zod-validator";
import { z } from "zod";
import { createSolverAdapter } from "../adapter/solver-adapter";
import type { SolverInput } from "@uptime/types";

const solver = new Hono();

/** Rate limiter: track requests per IP (simple in-memory implementation) */
const rateLimiter = new Map<string, { count: number; resetTime: number }>();
const RATE_LIMIT = 10; // requests per window
const RATE_WINDOW_MS = 60_000; // 1 minute

function checkRateLimit(ip: string): boolean {
  const now = Date.now();
  const entry = rateLimiter.get(ip);

  if (!entry || now > entry.resetTime) {
    rateLimiter.set(ip, { count: 1, resetTime: now + RATE_WINDOW_MS });
    return true;
  }

  if (entry.count >= RATE_LIMIT) {
    return false;
  }

  entry.count++;
  return true;
}

// Clean up old rate limit entries periodically
setInterval(() => {
  const now = Date.now();
  for (const [ip, entry] of rateLimiter.entries()) {
    if (now > entry.resetTime) {
      rateLimiter.delete(ip);
    }
  }
}, RATE_WINDOW_MS);

// Validation schemas
const solverEventSchema = z.object({
  id: z.string(),
  assetId: z.string(),
  maintenanceTypeId: z.string(),
  manHours: z.number().positive(),
  earliestPeriod: z.number().int().min(0),
  latestPeriod: z.number().int().min(0),
  targetPeriod: z.number().int().min(0),
  priority: z.number().int().min(1).max(10),
});

const solverInputSchema = z.object({
  events: z.array(solverEventSchema),
  assets: z.array(z.object({
    id: z.string(),
    assetNumber: z.string(),
    assetType: z.string(),
    carsCount: z.number().int().optional(),
    currentMileageKm: z.number(),
    avgDailyMileageKm: z.number(),
    lastMaintenanceDate: z.string().optional(),
    status: z.string().optional(),
    lastMaintenanceKm: z.record(z.string(), z.number()).optional(),
  })),
  maintenanceTypes: z.array(z.object({
    id: z.string(),
    level: z.enum(["A", "B", "C", "D"]),
    name: z.string(),
    description: z.string().optional(),
    intervalKm: z.number().positive(),
    toleranceKm: z.number().positive(),
    durationHours: z.number().positive(),
    manHours: z.number().positive(),
    requiredTracks: z.number().int().positive(),
    estimatedCost: z.number().min(0),
  })),
  constraints: z.object({
    weeklyManHours: z.number().positive(),
    monthlyManHours: z.number().positive(),
    maintenanceTracks: z.number().int().positive(),
    trackCapacityPerDay: z.number().int().positive(),
    depots: z.array(z.object({
      id: z.string(),
      name: z.string(),
      assetTypes: z.array(z.string()),
      trackCount: z.number().int().positive(),
      weeklyManHours: z.number().positive(),
    })),
  }),
  planningHorizonWeeks: z.number().int().positive(),
  objective: z.object({
    peakWorkloadWeight: z.number().optional(),
    levelingWeight: z.number().optional(),
    complianceWeight: z.number().optional(),
  }).optional(),
  settings: z.object({
    timeoutSeconds: z.number().positive().optional(),
    gapTolerance: z.number().min(0).max(1).optional(),
  }).optional(),
});

/**
 * POST /solve - Run the optimization solver
 */
solver.post(
  "/solve",
  zValidator("json", solverInputSchema),
  async (c) => {
    // Rate limiting
    const clientIp = c.req.header("x-forwarded-for") || "unknown";
    if (!checkRateLimit(clientIp)) {
      return c.json(
        {
          status: "ERROR",
          solution: null,
          metrics: null,
          diagnostics: {
            solverName: "HiGHS",
            solveTimeMs: 0,
            iterations: 0,
            warnings: ["Rate limit exceeded. Max 10 requests per minute."],
          },
        },
        429
      );
    }

    const input = c.req.valid("json") as SolverInput;

    try {
      // Create new adapter per request to prevent race conditions
      const adapter = createSolverAdapter();
      const startTime = performance.now();
      const result = await adapter.solve(input);
      const elapsed = performance.now() - startTime;

      return c.json({
        ...result,
        _meta: {
          totalTimeMs: elapsed,
          eventsCount: input.events.length,
          assetsCount: input.assets.length,
        },
      });
    } catch (error) {
      const message = error instanceof Error ? error.message : "Unknown error";
      return c.json(
        {
          status: "ERROR",
          solution: null,
          metrics: null,
          diagnostics: {
            solverName: "HiGHS",
            solveTimeMs: 0,
            iterations: 0,
            warnings: [message],
          },
        },
        500
      );
    }
  }
);

/**
 * GET /health - Health check for solver availability
 */
solver.get("/health", async (c) => {
  try {
    const adapter = createSolverAdapter();
    // Quick test solve with empty input
    const result = await adapter.solve({
      events: [],
      assets: [],
      maintenanceTypes: [],
      constraints: {
        weeklyManHours: 1000,
        monthlyManHours: 4000,
        maintenanceTracks: 1,
        trackCapacityPerDay: 1,
        depots: [],
      },
      planningHorizonWeeks: 1,
    });

    return c.json({
      status: "healthy",
      solver: result.diagnostics.solverName,
      responseTimeMs: result.diagnostics.solveTimeMs,
    });
  } catch (error) {
    const message = error instanceof Error ? error.message : "Unknown error";
    return c.json({ status: "unhealthy", error: message }, 503);
  }
});

export { solver };

import { useState, useEffect } from "react";
import {
  Card,
  Elevation,
  Tag,
  Intent,
  Icon,
  Spinner,
  Callout,
} from "@blueprintjs/core";
import { getFleetSummary, type FleetSummary } from "../lib/api";
import { getFleetSummary as getFallbackSummary, generateFleet, TOTAL_FLEET } from "../lib/demo-data";

export function Dashboard() {
  const [summary, setSummary] = useState<FleetSummary | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isLiveData, setIsLiveData] = useState(false);

  useEffect(() => {
    async function loadSummary() {
      try {
        const data = await getFleetSummary();
        setSummary(data);
        setIsLiveData(true);
      } catch (err) {
        // Fallback to demo data if API is not available
        console.warn("API not available, using demo data:", err);
        const fleet = generateFleet(TOTAL_FLEET);
        const fallback = getFallbackSummary(fleet);
        setSummary({
          total: fallback.total,
          alstomCount: fallback.alstomCount,
          kinkiCount: fallback.kinkiCount,
          avgMileage: fallback.avgMileage,
          alstomAvgMileage: fallback.alstomAvgMileage,
          kinkiAvgMileage: fallback.kinkiAvgMileage,
          operational: fallback.total,
          inMaintenance: 0,
        });
        setIsLiveData(false);
        setError("Using demo data - API not connected");
      } finally {
        setLoading(false);
      }
    }

    loadSummary();
  }, []);

  if (loading) {
    return (
      <div style={{ textAlign: "center", padding: "40px" }}>
        <Spinner size={40} />
        <p style={{ color: "#5f6b7c", marginTop: "16px" }}>Loading fleet data...</p>
      </div>
    );
  }

  if (!summary) {
    return (
      <Callout intent={Intent.DANGER} title="Failed to load data">
        Unable to load fleet summary.
      </Callout>
    );
  }

  return (
    <div>
      {error && (
        <Callout intent={Intent.WARNING} style={{ marginBottom: "16px" }}>
          {error}
        </Callout>
      )}

      {isLiveData && (
        <Callout intent={Intent.SUCCESS} icon="database" style={{ marginBottom: "16px" }}>
          Connected to database - showing live data
        </Callout>
      )}

      <div className="card-grid">
        <Card elevation={Elevation.TWO}>
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: "12px",
              marginBottom: "12px",
            }}
          >
            <Icon icon="train" size={20} />
            <span style={{ fontWeight: 500 }}>Total Fleet</span>
          </div>
          <div style={{ fontSize: "32px", fontWeight: 600, color: "#1c2127" }}>
            {summary.total}
          </div>
          <div style={{ color: "#5f6b7c", fontSize: "13px" }}>
            {summary.operational} operational, {summary.inMaintenance} in maintenance
          </div>
        </Card>

        <Card elevation={Elevation.TWO}>
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: "12px",
              marginBottom: "12px",
            }}
          >
            <Icon icon="drive-time" size={20} />
            <span style={{ fontWeight: 500 }}>Avg Mileage</span>
          </div>
          <div style={{ fontSize: "32px", fontWeight: 600, color: "#1c2127" }}>
            {summary.avgMileage.toLocaleString()}
          </div>
          <div style={{ color: "#5f6b7c", fontSize: "13px" }}>kilometers</div>
        </Card>

        <Card elevation={Elevation.TWO}>
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: "12px",
              marginBottom: "12px",
            }}
          >
            <Tag intent={Intent.PRIMARY}>Alstom</Tag>
          </div>
          <div style={{ fontSize: "32px", fontWeight: 600, color: "#1c2127" }}>
            {summary.alstomCount}
          </div>
          <div style={{ color: "#5f6b7c", fontSize: "13px" }}>
            Avg: {summary.alstomAvgMileage.toLocaleString()} km
          </div>
        </Card>

        <Card elevation={Elevation.TWO}>
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: "12px",
              marginBottom: "12px",
            }}
          >
            <Tag intent={Intent.SUCCESS}>Kinki Sharyo</Tag>
          </div>
          <div style={{ fontSize: "32px", fontWeight: 600, color: "#1c2127" }}>
            {summary.kinkiCount}
          </div>
          <div style={{ color: "#5f6b7c", fontSize: "13px" }}>
            Avg: {summary.kinkiAvgMileage.toLocaleString()} km
          </div>
        </Card>
      </div>

      <Card elevation={Elevation.TWO}>
        <h3 style={{ marginTop: 0 }}>Quick Actions</h3>
        <p style={{ color: "#5f6b7c" }}>
          Use the sidebar to navigate to different sections:
        </p>
        <ul style={{ color: "#5f6b7c", lineHeight: 1.8 }}>
          <li>
            <strong>Fleet</strong> - View all {summary.total} trains and their current status
          </li>
          <li>
            <strong>Schedule</strong> - View upcoming maintenance events
          </li>
          <li>
            <strong>Calendar</strong> - Visual calendar of scheduled maintenance
          </li>
          <li>
            <strong>What-If Simulator</strong> - Test different scheduling scenarios
          </li>
        </ul>
      </Card>
    </div>
  );
}

