import { useState, useEffect } from "react";
import {
  HTMLTable,
  Tag,
  Intent,
  Spinner,
  Callout,
  InputGroup,
  HTMLSelect,
} from "@blueprintjs/core";
import type { Asset } from "@uptime/types";
import { getFleet } from "../lib/api";
import { generateFleet, TOTAL_FLEET } from "../lib/demo-data";

export function FleetTable() {
  const [fleet, setFleet] = useState<Asset[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isLiveData, setIsLiveData] = useState(false);
  const [search, setSearch] = useState("");
  const [filterType, setFilterType] = useState<string>("all");

  useEffect(() => {
    async function loadFleet() {
      try {
        const { data } = await getFleet();
        setFleet(data);
        setIsLiveData(true);
      } catch (err) {
        console.warn("API not available, using demo data:", err);
        setFleet(generateFleet(TOTAL_FLEET));
        setIsLiveData(false);
        setError("Using demo data - API not connected");
      } finally {
        setLoading(false);
      }
    }

    loadFleet();
  }, []);

  if (loading) {
    return (
      <div style={{ textAlign: "center", padding: "40px" }}>
        <Spinner size={40} />
        <p style={{ color: "#5f6b7c", marginTop: "16px" }}>Loading fleet...</p>
      </div>
    );
  }

  // Filter fleet based on search and type filter
  const filteredFleet = fleet.filter((asset) => {
    const matchesSearch =
      search === "" ||
      asset.id.toLowerCase().includes(search.toLowerCase()) ||
      asset.assetNumber.toLowerCase().includes(search.toLowerCase());
    const matchesType =
      filterType === "all" || asset.assetType === filterType;
    return matchesSearch && matchesType;
  });

  return (
    <div>
      {error && (
        <Callout intent={Intent.WARNING} style={{ marginBottom: "16px" }}>
          {error}
        </Callout>
      )}

      {isLiveData && (
        <Callout
          intent={Intent.SUCCESS}
          icon="database"
          style={{ marginBottom: "16px" }}
        >
          Connected to database - showing live data ({fleet.length} trains)
        </Callout>
      )}

      <div
        style={{
          display: "flex",
          gap: "16px",
          marginBottom: "16px",
          alignItems: "center",
        }}
      >
        <InputGroup
          leftIcon="search"
          placeholder="Search by Train ID..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          style={{ width: "250px" }}
        />
        <HTMLSelect
          value={filterType}
          onChange={(e) => setFilterType(e.target.value)}
        >
          <option value="all">All Fleets</option>
          <option value="ALSTOM">Alstom</option>
          <option value="KINKI">Kinki Sharyo</option>
        </HTMLSelect>
        <span style={{ color: "#5f6b7c", marginLeft: "auto" }}>
          Showing {filteredFleet.length} of {fleet.length} trains
        </span>
      </div>

      <div style={{ overflowX: "auto" }}>
        <HTMLTable striped interactive style={{ width: "100%" }}>
          <thead>
            <tr>
              <th>Train ID</th>
              <th>Fleet</th>
              <th>Cars</th>
              <th>Current Mileage</th>
              <th>Avg Daily (km)</th>
              <th>Status</th>
            </tr>
          </thead>
          <tbody>
            {filteredFleet.map((asset) => (
              <tr key={asset.id}>
                <td>
                  <strong>{asset.id}</strong>
                </td>
                <td>
                  <Tag
                    intent={
                      asset.assetType === "ALSTOM"
                        ? Intent.PRIMARY
                        : Intent.SUCCESS
                    }
                  >
                    {asset.assetType === "ALSTOM" ? "Alstom" : "Kinki Sharyo"}
                  </Tag>
                </td>
                <td>{asset.carsCount}</td>
                <td>{asset.currentMileageKm.toLocaleString()} km</td>
                <td>{asset.avgDailyMileageKm} km</td>
                <td>
                  <Tag
                    intent={
                      asset.status === "operational"
                        ? Intent.SUCCESS
                        : asset.status === "in_maintenance"
                        ? Intent.WARNING
                        : Intent.DANGER
                    }
                    minimal
                  >
                    {asset.status === "operational"
                      ? "Operational"
                      : asset.status === "in_maintenance"
                      ? "In Maintenance"
                      : "Out of Service"}
                  </Tag>
                </td>
              </tr>
            ))}
          </tbody>
        </HTMLTable>
      </div>
    </div>
  );
}

